import os
import shutil
from django.conf import settings as django_settings
from django.core.management.base import BaseCommand
from content.models import Page, PageSection, SectionItem


IMAGES_SRC = os.path.join(django_settings.BASE_DIR, '..', 'ggrc', 'public', 'images')


def copy_image(relative_path, dest_subdir='seed'):
    src = os.path.normpath(os.path.join(IMAGES_SRC, relative_path))
    if not os.path.exists(src):
        return ''
    dest_rel = os.path.join(dest_subdir, relative_path).replace('\\', '/')
    dest_abs = os.path.join(django_settings.MEDIA_ROOT, dest_rel)
    os.makedirs(os.path.dirname(dest_abs), exist_ok=True)
    shutil.copy2(src, dest_abs)
    return dest_rel


