def _create_sections(page, language, sections_list, stdout):
    for i, sec_data in enumerate(sections_list):
        sec_kwargs = {
            'page': page,
            'section_type': sec_data['type'],
            'language': language,
            'order': i + 1,
            'title': sec_data.get('title', ''),
            'subtitle': sec_data.get('subtitle', ''),
            'settings': sec_data.get('settings', {}),
        }
        bg = sec_data.get('background_image')
        if bg:
            sec_kwargs['background_image'] = copy_image(bg)
        section = PageSection.objects.create(**sec_kwargs)

        for j, item in enumerate(sec_data.get('items', [])):
            item_kwargs = {
                'section': section,
                'order': j,
                'title': item.get('title', ''),
                'description': item.get('description', ''),
                'icon_name': item.get('icon_name', ''),
                'link_url': item.get('link_url', ''),
                'link_text': item.get('link_text', ''),
                'extra_data': item.get('extra_data', {}),
            }
            img = item.get('image')
            if img:
                item_kwargs['image'] = copy_image(img)
            SectionItem.objects.create(**item_kwargs)

    if stdout:
        stdout.write(f'  Created {len(sections_list)} sections for {page.slug} [{language}]')


class Command(BaseCommand):
    help = 'Seed RU and HY translations for existing page content'

    def handle(self, *args, **options):
        home = Page.objects.filter(slug='home').first()
        if not home:
            self.stdout.write(self.style.ERROR('Home page not found. Run seed_content first.'))
            return

        for lang in ('ru', 'am'):
            PageSection.objects.filter(page=home, language=lang).delete()

        self.stdout.write('Seeding RU translations...')
        _create_sections(home, 'ru', _build_home_ru(), self.stdout)

        self.stdout.write('Seeding AM translations...')
        _create_sections(home, 'am', _build_home_hy(), self.stdout)

        Page.objects.update_or_create(slug='services', defaults={'title': 'Services', 'order': 2})
        Page.objects.update_or_create(slug='team', defaults={'title': 'Our Team', 'order': 3})
        Page.objects.update_or_create(slug='blog', defaults={'title': 'Blog', 'order': 4})
        Page.objects.update_or_create(slug='contact', defaults={'title': 'Contact', 'order': 5})

        self.stdout.write(self.style.SUCCESS('Translations seeded successfully!'))
